```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// 函数实现
// ============================================

/**
 * Function: Test reactive calculation with dependencies
 *
 * @param a First input value
 * @param b Second input value
 * @return int The result of (a + b) * 2
 */
inline int test_reactive_calculation(int a, int b) {
    // 1. Create reactive variables
    auto var_a = reaction::MakeVar(a);
    auto var_b = reaction::MakeVar(b);

    // 2. Create reactive calculation
    // The reaction captures the variables and defines the logic (a + b) * 2
    auto calc = reaction::MakeReaction([var_a, var_b]() {
        return (var_a.Value() + var_b.Value()) * 2;
    });

    // 3. Return calculated result
    return calc.Value();
}

}  // namespace test_reaction
