inline RollbackObservation test_observer_state_rollback() {
    // 1. Create RecordingNode instances (and sensors)
    RecordingNode observer;
    reaction::ValueNode<int> sensor1;
    reaction::ValueNode<int> sensor2;

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    graph.attachNode(&observer);
    graph.attachNode(&sensor1);
    graph.attachNode(&sensor2);

    // 4. Set up initial dependency
    observer.addDependency(&sensor1);

    // 5. Save node state for rollback
    auto savedState = observer.saveState();

    // 6. Replace dependencies transactionally
    // We clear the old dependency and add the new one
    observer.clearDependencies();
    observer.addDependency(&sensor2);

    // 7. Trigger notification on second sensor
    sensor2.setValue(100);

    // 8. Record notification count after second binding
