    bool small_uses_sbo = small_resource.is_local();

    // 5. Query whether large resource uses SBO
    bool large_uses_sbo = large_resource.is_local();

    // 6. Return resource SBO state
    return ResourceSBOState{small_uses_sbo, large_uses_sbo};
