#include "test_conditional_mutex_behavior.h"

#include <reaction/concurrency/conditional_lock_guard.h>
#include <reaction/concurrency/conditional_mutex.h>
#include <reaction/concurrency/thread_manager.h>

namespace test_reaction {

ConditionalMutexResult test_conditional_mutex_behavior() {
    ConditionalMutexResult result = {false, false};

    // 1. Get thread manager instance
    auto& thread_manager = reaction::concurrency::ThreadManager::get_instance();

    // 2. Reset thread manager state
    // We ensure thread safety is disabled to start from a known state.
    thread_manager.set_thread_safety(false);

    // 3. Create ConditionalMutex instance
    reaction::concurrency::ConditionalMutex mutex;

    // 4. Create ConditionalLockGuard in a scope block
    {
        reaction::concurrency::ConditionalLockGuard guard(mutex);

        // 5. Attempt to lock mutex without safety enabled
        // When safety is disabled, the mutex operations are no-ops.
        // The guard calls lock() (no-op), so try_lock() should succeed (return true).
        result.tryLockWithoutSafety = mutex.try_lock();

        // If try_lock succeeded, we must unlock to maintain balance if logic changes,
        // though strictly it's a no-op here.
        if (result.tryLockWithoutSafety) {
            mutex.unlock();
        }
    } 
    // 6. Exit guard scope (guard destructor called here)

    // 7. Enable thread safety
    thread_manager.set_thread_safety(true);

    // 8. Create ConditionalLockGuard in a scope block again
    {
        reaction::concurrency::ConditionalLockGuard guard(mutex);

        // 9. Attempt to lock mutex with safety enabled
        // When safety is enabled, the guard holds a real lock.
        // Therefore, try_lock() should fail (return false) because the mutex is already locked by this thread.
        result.tryLockWithSafety = mutex.try_lock();

        if (result.tryLockWithSafety) {
            mutex.unlock();
        }
    } 
    // 10. Exit guard scope (guard destructor called here)

    // 11. Return conditional mutex result
    return result;
}

}  // namespace test_reaction
