#pragma once

#include <reaction/reaction.h>
#include <set>
#include <string>
#include <vector>
#include <algorithm>

namespace test_reaction {

struct OrderingSnapshot {
    std::vector<std::string> orderedNames;
    bool allUnique;
};

/**
 * Function: Demonstrate React::operator< for ordering reactive handles.
 *
 * @param firstName Name assigned to the first reactive node
 * @param secondName Name assigned to the second reactive node
 * @param thirdName Name assigned to the third reactive node
 * @return OrderingSnapshot Snapshot of sorted names and uniqueness flag
 */
inline OrderingSnapshot test_react_ordering(const std::string &firstName,
                                            const std::string &secondName,
                                            const std::string &thirdName) {
    // 1. Create three reactive variables with names
    reaction::Value<std::string> v1(firstName);
    reaction::Value<std::string> v2(secondName);
    reaction::Value<std::string> v3(thirdName);

    // 2. Insert them into a set
    // This implicitly uses the library's operator< to order the handles
    // (usually by creation ID or memory address), not by the string value.
    std::set<reaction::Value<std::string>> handleSet;
    handleSet.insert(v1);
    handleSet.insert(v2);
    handleSet.insert(v3);

    OrderingSnapshot snapshot;

    // 3. Collect ordered names
    // We iterate through the set, which is sorted by the reactive handle,
    // and extract the names in that specific order.
    for (const auto& handle : handleSet) {
        snapshot.orderedNames.push_back(handle.value());
    }

    // 4. Check if all names are unique
    // We sort a copy of the names to check for duplicates efficiently.
    std::vector<std::string> checkVector = snapshot.orderedNames;
    std::sort(checkVector.begin(), checkVector.end());
    auto last = std::unique(checkVector.begin(), checkVector.end());

    snapshot.allUnique = (last == checkVector.end());

    // 5. Return ordering snapshot
    return snapshot;
}

}  // namespace test_reaction
