#pragma once

#include <reaction/reaction.h>
#include <cstdint>

namespace test_reaction {

struct AtomicCompoundSnapshot {
    int afterAddition;
    int afterMultiplication;
    int afterBitwiseAnd;
    int afterShift;
    int postIncrementReturn;
    int finalValue;
    int calcEvaluations;
};

/**
 * Function: Demonstrate atomic compound assignments on a reactive counter.
 *
 * @return AtomicCompoundSnapshot Snapshot with values after each compound operation.
 */
inline AtomicCompoundSnapshot test_atomic_compound_assign() {
    AtomicCompoundSnapshot snapshot;

    // 1. Create reactive variable (Initialize with 10)
    reaction::Value<int> var(10);

    // 2. Create counter to track calculation evaluations
    int eval_counter = 0;

    // 3. Create calculation to track value
    // The lambda executes immediately to establish dependencies.
    auto calc = reaction::MakeCalc([&] {
        eval_counter++;
        return var.Get();
    });

    // 4. Apply atomic addition
    var += 5; // 10 + 5 = 15

    // 5. Get value after addition
    snapshot.afterAddition = var.Get();

    // 6. Apply atomic multiplication
    var *= 2; // 15 * 2 = 30

    // 7. Get value after multiplication
    snapshot.afterMultiplication = var.Get();

    // 8. Apply atomic bitwise AND
    // 30 (11110) & 15 (01111) = 14 (01110)
    var &= 0x0F;

    // 9. Get value after bitwise AND
    snapshot.afterBitwiseAnd = var.Get();

    // 10. Apply atomic left shift
    var <<= 1; // 14 << 1 = 28

    // 11. Get value after shift
    snapshot.afterShift = var.Get();

    // 12. Apply post-increment
    // Returns the value before increment (28), sets var to 29
    snapshot.postIncrementReturn = var++;

    // 13. Get final value
    snapshot.finalValue = var.Get();

    // Ensure the calculation is updated (if lazy) and capture the evaluation count
    calc.Get(); 
    snapshot.calcEvaluations = eval_counter;

    // 14. Return atomic compound snapshot
    return snapshot;
}

}  // namespace test_reaction
